local jwt = require "resty.jwt"
local cjson = require "cjson.safe"

local JWT_SECRET = os.getenv("JWT_SECRET") or "CHANGE_THIS_SECRET_IN_PRODUCTION"
local AUTH_HEADER = ngx.var.http_authorization

local function deny_access(message, status)
    ngx.status = status or ngx.HTTP_FORBIDDEN
    ngx.header.content_type = "application/json"
    ngx.say(cjson.encode({error = message}))
    ngx.exit(status or ngx.HTTP_FORBIDDEN)
end

local function validate_token(token)
    if not token or token == "" then
        return nil, "Missing authentication token"
    end
    
    local jwt_obj = jwt:verify(JWT_SECRET, token)
    
    if not jwt_obj or not jwt_obj.verified then
        return nil, "Invalid or expired token"
    end
    
    if not jwt_obj.payload then
        return nil, "Invalid token payload"
    end
    
    return jwt_obj.payload, nil
end

local function check_role_permission(user_role, required_role)
    if not user_role or user_role == "" then
        return false
    end
    
    if not required_role or required_role == "" then
        return false
    end
    
    local role_hierarchy = {
        admin = 3,
        moderator = 2,
        user = 1,
        guest = 0
    }
    
    local user_level = role_hierarchy[user_role] or 0
    local required_level = role_hierarchy[required_role] or 0
    
    return user_level >= required_level
end

local function is_protected_endpoint(uri)
    if not uri then
        return true
    end
    
    local public_endpoints = {
        "^/health$",
        "^/status$",
        "^/public/",
        "^/login$",
        "^/register$"
    }
    
    for _, pattern in ipairs(public_endpoints) do
        if ngx.re.match(uri, pattern, "jo") then
            return false
        end
    end
    
    return true
end

local function get_required_role(uri)
    if not uri then
        return "admin"
    end
    
    if ngx.re.match(uri, "^/admin", "jo") then
        return "admin"
    end
    
    if ngx.re.match(uri, "^/api", "jo") then
        return "user"
    end
    
    return "user"
end

local uri = ngx.var.uri

if not is_protected_endpoint(uri) then
    return
end

if not AUTH_HEADER or AUTH_HEADER == "" then
    deny_access("Authentication required", ngx.HTTP_UNAUTHORIZED)
end

local token = string.match(AUTH_HEADER, "^Bearer%s+(.+)$")

if not token then
    deny_access("Invalid authorization header format", ngx.HTTP_UNAUTHORIZED)
end

local payload, err = validate_token(token)

if err then
    deny_access(err, ngx.HTTP_UNAUTHORIZED)
end

if not payload.sub or payload.sub == "" then
    deny_access("Invalid token: missing user identifier", ngx.HTTP_UNAUTHORIZED)
end

if not payload.role or payload.role == "" then
    deny_access("Invalid token: missing user role", ngx.HTTP_FORBIDDEN)
end

local required_role = get_required_role(uri)

if not check_role_permission(payload.role, required_role) then
    deny_access("Insufficient permissions", ngx.HTTP_FORBIDDEN)
end

ngx.req.set_header("X-User-ID", payload.sub)
ngx.req.set_header("X-User-Role", payload.role)